import React, { useState, useCallback } from 'react';
import { upscaleImage } from './services/geminiService';
import { fileToBase64 } from './utils/fileUtils';
import { UploadIcon, SparklesIcon, LoadingSpinner, ErrorIcon } from './components/Icons';
import ImageComparisonSlider from './components/ImageComparisonSlider';

type Quality = 'Standard' | 'High' | 'Professional';

const MAX_FILE_SIZE_MB = 10;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024; // 10MB in bytes

const App: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [originalImageFile, setOriginalImageFile] = useState<File | null>(null);
  const [upscaledImage, setUpscaledImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [enhanceFaces, setEnhanceFaces] = useState<boolean>(true);
  const [outputQuality, setOutputQuality] = useState<Quality>('High');


  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      resetState(); // Reset previous state

      if (file.size > MAX_FILE_SIZE_BYTES) {
        setError(`File size exceeds the limit of ${MAX_FILE_SIZE_MB}MB.`);
        // Clear the file input to allow re-selection
        const fileInput = document.getElementById('file-upload') as HTMLInputElement;
        if(fileInput) fileInput.value = '';
        return;
      }

      setOriginalImageFile(file);
      try {
        const base64 = await fileToBase64(file);
        setOriginalImage(base64);
      } catch (err) {
        setError('Could not read the selected file.');
        console.error(err);
      }
    }
  };

  const handleUpscale = useCallback(async () => {
    if (!originalImage) {
      setError('Please select an image first.');
      return;
    }

    // The base64 string includes the data URL prefix, which needs to be removed.
    const base64Data = originalImage.split(',')[1];
    if (!base64Data || !originalImageFile) {
        setError('Invalid image format.');
        return;
    }

    setIsLoading(true);
    setError(null);
    setUpscaledImage(null);

    try {
      const upscaledBase64 = await upscaleImage(base64Data, originalImageFile.type, enhanceFaces, outputQuality);
      setUpscaledImage(`data:image/png;base64,${upscaledBase64}`);
    } catch (err: any) { // Catch potential timeout or other API errors
      console.error(err);
      if (err.message && err.message.includes("timed out")) {
        setError('Upscaling took too long and timed out. Please try again or use a smaller/simpler image.');
      } else {
        setError('Failed to upscale image. This might be due to an issue with the image itself, an API error, or temporary model unavailability. Please try again with a different image or later.');
      }
    } finally {
      setIsLoading(false);
    }
  }, [originalImage, originalImageFile, enhanceFaces, outputQuality]);

  const resetState = () => {
      setOriginalImage(null);
      setOriginalImageFile(null);
      setUpscaledImage(null);
      setError(null);
      setIsLoading(false);
  };

  const handleReset = () => {
      resetState();
      // Also clear the file input
      const fileInput = document.getElementById('file-upload') as HTMLInputElement;
      if(fileInput) fileInput.value = '';
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center p-4 sm:p-6 lg:p-8">
      <header className="w-full max-w-6xl text-center mb-8">
        <h1 className="text-4xl sm:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-cyan-400">
          Gemini Image Upscaler
        </h1>
        <p className="mt-2 text-lg text-gray-400">
          A high-fidelity image upscaler for pros. Restore sharpness, definition, and details with expert precision.
        </p>
      </header>

      <main className="w-full max-w-6xl flex-grow flex flex-col items-center">
        <div className="w-full bg-gray-800/50 rounded-2xl shadow-2xl p-6 border border-gray-700 backdrop-blur-sm">
          {!originalImage && (
            <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-gray-600 rounded-lg p-6 text-center">
                <UploadIcon className="w-16 h-16 text-gray-500 mb-4" />
                <label
                    htmlFor="file-upload"
                    className="cursor-pointer font-semibold text-purple-400 hover:text-purple-300 transition-colors"
                >
                    <span>Upload an image</span>
                    <input id="file-upload" name="file-upload" type="file" className="sr-only" accept="image/*" onChange={handleFileChange} />
                </label>
                <p className="text-xs text-gray-500 mt-1">PNG, JPG, GIF up to {MAX_FILE_SIZE_MB}MB</p>
            </div>
          )}

          {originalImage && (
            <div className="flex flex-col items-center gap-6">
                <div className="w-full max-w-3xl">
                    <h3 className="text-lg font-semibold text-center mb-3 text-gray-300">Original vs. Upscaled</h3>
                    <div className="aspect-square bg-gray-900 rounded-lg overflow-hidden border border-gray-700 flex items-center justify-center relative">
                        { !upscaledImage && originalImage && (
                            <img src={originalImage} alt="Original" className="max-w-full max-h-full object-contain" />
                        )}
                        { upscaledImage && originalImage && (
                            <ImageComparisonSlider beforeImage={originalImage} afterImage={upscaledImage} />
                        )}

                        {isLoading && (
                            <div className="absolute inset-0 bg-black/50 flex flex-col items-center justify-center z-10">
                                <LoadingSpinner className="w-12 h-12 text-purple-400" />
                                <p className="mt-2 text-sm">Upscaling...</p>
                            </div>
                        )}
                        {error && !isLoading && (
                            <div className="absolute inset-0 bg-black/50 flex flex-col items-center justify-center z-10 p-4 text-center">
                                <ErrorIcon className="w-12 h-12 text-red-500 mb-2" />
                                <p className="text-sm text-red-400">{error}</p>
                            </div>
                        )}
                    </div>
                </div>
              <div className="flex flex-col items-center justify-center gap-4 mt-4 w-full">
                <div className="flex flex-col sm:flex-row items-center gap-6">
                    <div className="flex items-center gap-2">
                        <input
                            id="face-enhancement"
                            name="face-enhancement"
                            type="checkbox"
                            checked={enhanceFaces}
                            onChange={(e) => setEnhanceFaces(e.target.checked)}
                            className="h-4 w-4 rounded border-gray-500 bg-gray-700 text-purple-500 focus:ring-purple-600 focus:ring-offset-gray-800 cursor-pointer"
                        />
                        <label htmlFor="face-enhancement" className="text-sm font-medium text-gray-300 cursor-pointer">
                            Face Restoration
                        </label>
                    </div>
                     <div className="flex items-center gap-2">
                        <label htmlFor="output-quality" className="text-sm font-medium text-gray-300">
                            Output Quality
                        </label>
                        <select
                            id="output-quality"
                            name="output-quality"
                            value={outputQuality}
                            onChange={(e) => setOutputQuality(e.target.value as Quality)}
                            className="rounded border-gray-500 bg-gray-700 text-white text-sm focus:ring-purple-600 focus:border-purple-600 focus:ring-offset-gray-800 cursor-pointer py-1 pr-8"
                        >
                            <option>Standard</option>
                            <option>High</option>
                            <option>Professional</option>
                        </select>
                    </div>
                </div>
                <div className="flex flex-wrap items-center justify-center gap-4 mt-4">
                    <button
                        onClick={handleUpscale}
                        disabled={isLoading || !originalImage}
                        className="flex items-center gap-2 px-6 py-3 bg-purple-600 text-white font-semibold rounded-lg shadow-md hover:bg-purple-700 transition-all duration-200 disabled:bg-gray-500 disabled:cursor-not-allowed"
                    >
                        <SparklesIcon className="w-5 h-5" />
                        {isLoading ? 'Upscaling...' : 'Upscale 2x'}
                    </button>

                    {upscaledImage && (
                        <a
                        href={upscaledImage}
                        download={`upscaled-2x-${originalImageFile?.name || 'image.png'}`}
                        className="px-6 py-3 bg-green-600 text-white font-semibold rounded-lg shadow-md hover:bg-green-700 transition-all duration-200"
                        >
                        Download
                        </a>
                    )}

                    <button
                        onClick={handleReset}
                        className="px-6 py-3 bg-gray-600 text-white font-semibold rounded-lg shadow-md hover:bg-gray-700 transition-all duration-200"
                    >
                        Reset
                    </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

