import { GoogleGenAI } from "@google/genai";

const API_CALL_TIMEOUT_MS = 60000; // 60 seconds (1 minute)

export const upscaleImage = async (
  base64ImageData: string,
  mimeType: string,
  enhanceFaces: boolean,
  quality: 'Standard' | 'High' | 'Professional'
): Promise<string> => {
  try {
    const API_KEY = process.env.API_KEY;

    if (!API_KEY) {
      throw new Error("API_KEY environment variable not set. Please ensure an API key is selected.");
    }

    // Instantiate GoogleGenAI here to ensure it uses the latest API_KEY
    const ai = new GoogleGenAI({ apiKey: API_KEY });

    let promptText = `You are an expert digital image restoration engineer. Your task is to perform a high-fidelity 2x upscale. The final output must be a lossless image with visibly increased sharpness, clarity, and detail, achieved through intelligent analysis, not just simple sharpening filters. It is critical to avoid artificial-looking results, halos, or amplified noise.`;

    const qualityInstructions = {
      Standard: `
Perform a 2x upscale. Reduce noise and common compression artifacts. Apply smart sharpening to enhance clarity and define major details, ensuring a clear and crisp improvement over the original.`,
      High: `
Perform a high-fidelity 2x upscale. Effectively suppress compression artifacts and noise while preserving fine textures. Apply selective detail enhancement to bring out subtle elements and sharpen critical edges, avoiding any unnatural halos.`,
      Professional: `
Perform a professional-grade 2x upscale. Meticulously eliminate digital artifacts and intelligently reconstruct latent details to achieve a natively high-resolution appearance. Ensure photorealistic sharpness, clarity, and texture fidelity with advanced artifact control.`
    };

    promptText += "\n" + qualityInstructions[quality];

    if (enhanceFaces) {
      promptText += `
For any faces present in the image, prioritize natural reconstruction of skin texture, hair, and eye clarity. The goal is photorealistic restoration, maintaining the original identity and expression without artificial smoothing or alteration of features.`;
    }

    const timeoutPromise = new Promise<never>((_, reject) =>
      setTimeout(() => reject(new Error("API call timed out after 60 seconds.")), API_CALL_TIMEOUT_MS)
    );

    const response = await Promise.race([
      ai.models.generateContent({
        model: 'gemini-2.5-flash-image', // Reverted model to gemini-2.5-flash-image
        contents: {
          parts: [
            {
              inlineData: {
                data: base64ImageData,
                mimeType: mimeType,
              },
            },
            {
              text: promptText,
            },
          ],
        },
      }),
      timeoutPromise
    ]);

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }

    throw new Error("No image data found in the API response.");
  } catch (error: any) {
    console.error("Error calling Gemini API:", error);
    if (error.message && error.message.includes("timed out")) {
      throw new Error("API call timed out after 60 seconds. The model took too long to respond.");
    }
    // Specific error message for API key issues
    if (error.message && error.message.includes("API key not valid") || 
        error.message.includes("Requested entity was not found.")) { // Common for invalid/expired keys
      throw new Error("Requested entity was not found. This typically means the API key is invalid or not correctly configured for billing. Please re-select your API key.");
    }
    // Provide a more user-friendly error message for other issues
    throw new Error("Failed to upscale image. This might be due to an issue with the image itself, an API error, or temporary model unavailability. Please try again with a different image or later.");
  }
};

