import { GoogleGenAI } from "@google/genai";

const API_CALL_TIMEOUT_MS = 60000; // 60 seconds (1 minute)

export const upscaleImage = async (
  base64ImageData: string,
  mimeType: string,
  enhanceFaces: boolean,
  quality: 'Standard' | 'High' | 'Professional'
): Promise<string> => {
  try {
    const API_KEY = process.env.API_KEY;

    if (!API_KEY) {
      throw new Error("API_KEY environment variable not set. Please ensure an API key is selected.");
    }

    // Instantiate GoogleGenAI here right before making the call as per Pro model guidelines
    const ai = new GoogleGenAI({ apiKey: API_KEY });

    let promptText = `You are a world-class digital image restoration and enhancement engine. Your task is to perform a high-fidelity 2x upscale of the provided image. 

The final output MUST be a lossless image with significantly increased sharpness, clarity, and detail. Use your advanced reasoning capabilities to intelligently reconstruct missing information, textures, and edges, rather than just applying simple sharpening filters. It is critical to achieve a natively high-resolution look without artificial halos, plastic-looking skin, or amplified noise.`;

    const qualityInstructions = {
      Standard: `
Instruction: Perform a high-quality 2x upscale. Reduce common compression artifacts and noise while maintaining natural edges.`,
      High: `
Instruction: Perform a high-fidelity 2x upscale. Suppress artifacts and reconstruct latent fine textures. Ensure selective detail enhancement to bring out subtle elements in the scene.`,
      Professional: `
Instruction: Perform a professional-grade 2x upscale. Meticulously eliminate digital artifacts and intelligently reconstruct complex details to achieve a natively high-resolution appearance. Ensure photorealistic sharpness and texture fidelity across all regions.`
    };

    promptText += "\n" + qualityInstructions[quality];

    if (enhanceFaces) {
      promptText += `
Special Face Restoration: If any human faces are present, prioritize the photorealistic reconstruction of skin texture, hair strands, and eye clarity. Maintain the original identity and expression exactly, avoiding any unnatural smoothing or distortion.`;
    }

    const timeoutPromise = new Promise<never>((_, reject) =>
      setTimeout(() => reject(new Error("API call timed out after 60 seconds.")), API_CALL_TIMEOUT_MS)
    );

    const response = await Promise.race([
      ai.models.generateContent({
        model: 'gemini-3-pro-image-preview', // Switched to Gemini 3 Pro
        contents: {
          parts: [
            {
              inlineData: {
                data: base64ImageData,
                mimeType: mimeType,
              },
            },
            {
              text: promptText,
            },
          ],
        },
        config: {
          // Gemini 3 Pro Image specific config
          imageConfig: {
            aspectRatio: "1:1", // The model usually respects the input image's aspect ratio for editing tasks
            imageSize: "1K"
          }
        }
      }),
      timeoutPromise
    ]);

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }

    throw new Error("No image data found in the API response.");
  } catch (error: any) {
    console.error("Error calling Gemini API:", error);

    if (error.message && error.message.includes("timed out")) {
      throw new Error("API call timed out after 60 seconds. The Pro model took too long to process this request.");
    }

    // Handle the specific "Requested entity was not found" error by asking to re-select key
    if (error.message && (error.message.includes("API key not valid") || 
        error.message.includes("Requested entity was not found."))) {
      throw new Error("Requested entity was not found. This typically means the API key is invalid or from a project without billing enabled. Please re-select a valid paid API key.");
    }

    throw new Error("Failed to upscale image with Gemini 3 Pro. Please try again with a different image or later.");
  }
};

