        setApiKeySelected(hasKey);
        // Guidelines for Gemini 3 Pro state mandatory key selection before accessing the app.
        // We'll show the prompt if no key is detected on mount.
        if (!hasKey) {
          setShowApiKeyPrompt(true);
        }
      } else {
        const hasEnvKey = !!process.env.API_KEY;
